// Select best-matching music track from library based on mood tags
const input = $input.first().json;
const topicId = input.topic_id;
const targetMood = input.music_mood || 'reflective'; // from script music_sections
const isShortForm = input.short_form || false;

// Fetch music library
const tracks = await this.helpers.httpRequest({
  method: 'GET',
  url: `${process.env.SUPABASE_URL}/rest/v1/music_library?select=*&order=created_at.desc`,
  headers: {
    'apikey': process.env.SUPABASE_ANON_KEY,
    'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}`,
  },
});

if (!tracks || tracks.length === 0) {
  return [{ json: { success: false, error: 'No tracks in music_library', topic_id: topicId } }];
}

// Score tracks by mood tag match
const scored = tracks.map(t => {
  const tags = t.mood_tags || [];
  const score = tags.includes(targetMood) ? 10 :
    tags.some(tag => targetMood.includes(tag) || tag.includes(targetMood)) ? 5 : 1;
  return { ...t, match_score: score };
}).sort((a, b) => b.match_score - a.match_score);

const selected = scored[0];

// Ducking volume: short-form = 0.08-0.10, long-form = 0.12
const duckVolume = isShortForm ? '0.08' : '0.12';

return [{ json: {
  success: true,
  topic_id: topicId,
  track_id: selected.id,
  track_title: selected.title,
  track_url: selected.file_url,
  track_drive_id: selected.file_drive_id,
  match_score: selected.match_score,
  target_mood: targetMood,
  duck_volume: duckVolume,
  is_short_form: isShortForm,
} }];
